I made a temporary workaround for this issue:
```
diff --git a/pkg/specgen/generate/namespaces.go b/pkg/specgen/generate/namespaces.go
index 1d7373093..97e941a6d 100644
--- a/pkg/specgen/generate/namespaces.go
+++ b/pkg/specgen/generate/namespaces.go
@@ -73,6 +73,23 @@ func GetDefaultNamespaceMode(nsType string, cfg *config.Config, pod *libpod.Pod)
 	return toReturn, errors.Wrapf(define.ErrInvalidArg, "invalid namespace type %q passed", nsType)
 }

+func getUsedPorts(rt *libpod.Runtime) (map[int32]bool, error) {
+	cnts, err := rt.GetAllContainers()
+	if err != nil {
+		return nil, err
+	}
+	used_ports := make(map[int32]bool)
+	for _, cnt := range cnts {
+		mapping, err := cnt.PortMappings()
+		if err != nil {
+			return nil, err
+		}
+		for _, mp := range mapping {
+			used_ports[mp.HostPort] = true
+		}
+	}
+	return used_ports, nil
+}
 // namespaceOptions generates container creation options for all
 // namespaces in a SpecGenerator.
 // Pod is the pod the container will join. May be nil is the container is not
@@ -242,7 +259,11 @@ func namespaceOptions(ctx context.Context, s *specgen.SpecGenerator, rt *libpod.
 		}
 		toReturn = append(toReturn, libpod.WithNetNSFrom(netCtr))
 	case specgen.Slirp:
-		portMappings, err := createPortMappings(ctx, s, imageData)
+		used_ports, err := getUsedPorts(rt)
+		if err != nil {
+			return nil, err
+		}
+		portMappings, err := createPortMappings(ctx, s, imageData, used_ports)
 		if err != nil {
 			return nil, err
 		}
@@ -254,7 +275,11 @@ func namespaceOptions(ctx context.Context, s *specgen.SpecGenerator, rt *libpod.
 	case specgen.Private:
 		fallthrough
 	case specgen.Bridge:
-		portMappings, err := createPortMappings(ctx, s, imageData)
+		used_ports, err := getUsedPorts(rt)
+		if err != nil {
+			return nil, err
+		}
+		portMappings, err := createPortMappings(ctx, s, imageData, used_ports)
 		if err != nil {
 			return nil, err
 		}
